import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import './css/Login.css';
import logoImage from '../assets/aqi.webp'; 

function Login() {
  const [phoneNumber, setPhoneNumber] = useState('');
  const [otp, setOtp] = useState('');
  const [showOTP, setShowOTP] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [isMobileView, setIsMobileView] = useState(window.innerWidth <= 768);
  
  const navigate = useNavigate();

  const API_BASE_URL = process.env.NODE_ENV === 'production' 
    ? 'https://airaware-app-gcw7.onrender.com' 
    : 'http://localhost:8000';

  const createParticles = () => {
    const particles = [];
    for (let i = 0; i < 20; i++) {
      particles.push(
        <div
          key={i}
          className="particle"
          style={{
            left: Math.random() * 100 + '%',
            top: Math.random() * 100 + '%',
            width: '4px',
            height: '4px',
            backgroundColor: 'rgba(59, 130, 246, 0.3)',
            borderRadius: '50%',
            position: 'absolute',
            animationDelay: Math.random() * 5 + 's'
          }}
        />
      );
    }
    return particles;
  };

  const clearMessages = () => {
    setError('');
    setSuccess('');
  };

  const validatePhoneNumber = (phone) => {
    const cleanPhone = phone.replace(/[^\d+]/g, '');
    
    if (cleanPhone.length === 13 && cleanPhone.startsWith('+91')) {
      const numberPart = cleanPhone.substring(3);
      if (numberPart.length === 10 && numberPart.match(/^[6-9]/)) {
        return cleanPhone;
      }
    }
    
    return null;
  };

  const handlePhoneNumberChange = (e) => {
    let value = e.target.value;
    
    value = value.replace(/[^\d+]/g, '');
    
    if (value.length > 0 && !value.startsWith('+91')) {
      if (value.match(/^\d/)) {
        value = '+91' + value;
      }
    }
    
    if (!value.startsWith('+91') && value.length > 0) {
      value = '+91';
    }
    
    if (value.length > 13) {
      value = value.substring(0, 13);
    }
    
    setPhoneNumber(value);
    clearMessages();
  };

  const handleOTPChange = (e) => {
    const value = e.target.value.replace(/\D/g, '').slice(0, 6);
    setOtp(value);
    clearMessages();
  };

  // Auto-hide error after 2.5 seconds
  useEffect(() => {
    if (error) {
      const timer = setTimeout(() => setError(''), 2500);
      return () => clearTimeout(timer);
    }
  }, [error]);

  useEffect(() => {
    const handleResize = () => {
      const width = window.innerWidth;
      setIsMobileView(width <= 768);
    };

    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const handleSendOTP = async (e) => {
    e.preventDefault();
    
    console.log('Send OTP clicked');
    
    if (loading) return;
    
    setLoading(true);
    clearMessages();

    try {
      const validatedPhone = validatePhoneNumber(phoneNumber);
      
      if (!validatedPhone) {
        setError('Please enter a valid phone number with +91 prefix (e.g., +919876543210)');
        setLoading(false);
        return;
      }

      console.log('Sending OTP to:', validatedPhone);

      const response = await fetch(`${API_BASE_URL}/api/send-otp/`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ phone_number: validatedPhone }),
      });

      const data = await response.json();
      console.log('Send OTP Response:', data);

      if (response.ok && data.success) {
        setShowOTP(true);
        setSuccess('OTP sent successfully! Check your phone.');
        setPhoneNumber(validatedPhone);
      } else {
        setError(data.error || data.message || 'Failed to send OTP');
      }
    } catch (err) {
      console.error('Send OTP Error:', err);
      setError('Network error. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  // FIXED: Improved OTP verification with reliable redirect
  const handleVerifyOTP = async (e) => {
    e.preventDefault();
    
    console.log('🔄 Starting OTP verification...');
    
    if (loading) return;
    
    setLoading(true);
    clearMessages();

    try {
      if (!otp || otp.length !== 6) {
        setError('Please enter a valid 6-digit OTP');
        setLoading(false);
        return;
      }

      console.log('📤 Sending verification request:', { otp, phoneNumber });

      const response = await fetch(`${API_BASE_URL}/api/verify-otp/`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ 
          otp_code: otp, 
          phone_number: phoneNumber 
        }),
      });

      const data = await response.json();
      console.log('📨 Backend response:', data);

      if (response.ok && data.success) {
        console.log('✅ OTP verification successful!');
        
        // Store user data in localStorage
        localStorage.setItem('user', JSON.stringify(data.user));
        localStorage.setItem('isLoggedIn', 'true');
        localStorage.setItem('loginTime', Date.now().toString());
        
        setSuccess('Login successful! Redirecting...');
        
        // FIXED: Direct navigation without setTimeout
        console.log('🎯 Determining redirect path...');
        console.log('- Backend redirect_to:', data.redirect_to);
        console.log('- User has health assessment:', data.user.has_health_assessment);
        
        // Clear any existing navigation state
        setLoading(false);
        
        // FIXED: More reliable redirect logic
        let redirectPath = '/dashboard'; // Default fallback
        
        // Priority 1: Use backend's explicit redirect instruction
        if (data.redirect_to) {
          redirectPath = data.redirect_to;
          console.log('📍 Using backend redirect:', redirectPath);
        } 
        // Priority 2: Use health assessment status
        else if (data.user && typeof data.user.has_health_assessment === 'boolean') {
          redirectPath = data.user.has_health_assessment ? '/dashboard' : '/health-assessment';
          console.log('📍 Using health assessment status:', redirectPath);
        }
        // Priority 3: Check debug info
        else if (data.debug_info && typeof data.debug_info.health_assessment_found === 'boolean') {
          redirectPath = data.debug_info.health_assessment_found ? '/dashboard' : '/health-assessment';
          console.log('📍 Using debug info:', redirectPath);
        }
        
        console.log('🚀 Final redirect path:', redirectPath);
        
        // FIXED: Use a very short delay to ensure state updates are complete
        setTimeout(() => {
          console.log('🔄 Executing navigation to:', redirectPath);
          navigate(redirectPath, { replace: true });
        }, 500); // Reduced from 1500ms to 500ms
        
      } else {
        console.log('❌ OTP verification failed:', data);
        setError(data.error || data.message || 'Invalid OTP. Please try again.');
      }
    } catch (err) {
      console.error('💥 Network error during OTP verification:', err);
      setError('Network error. Please check your connection and try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleBackToPhone = () => {
    setShowOTP(false);
    setOtp('');
    clearMessages();
  };

  return (
    <div className="login-page">
      {/* Navbar */}
      <nav className="navbar">
        <div className="navbar-content">
          <Link to="/" className="navbar-brand">
            <img src={logoImage} alt="AQM Logo" width={isMobileView ? "32" : "40"} height={isMobileView ? "32" : "40"} />
            AirAware
          </Link>
        </div>
      </nav>

      {/* Login Section */}
      <section className="login-section">
        <div className="particles">
          {createParticles()}
        </div>
        
        <div className="login-container">
          <div className="login-header">
            <h2>
              👤 {showOTP ? 'Verify OTP' : 'Login'}
            </h2>
            <p>
              {showOTP 
                ? `Enter the 6-digit OTP sent to ${phoneNumber}` 
                : 'Welcome back! Please log in to your account.'
              }
            </p>
            <li><Link to="/">🏠 Home</Link></li>
          </div>

          {/* Success message */}
          {success && (
            <div className="success-message">
              <span>✅</span>
              <span>{success}</span>
            </div>
          )}

          {/* Error message with close button */}
          {error && (
            <div className="error-message">
              <span>⚠️</span>
              <span>{error}</span>
              <button className="alert-close" onClick={() => setError("")}>×</button>
            </div>
          )}

          {!showOTP ? (
            // Phone Number Form
            <form onSubmit={handleSendOTP}>
              <div className="form-group">
                <label htmlFor="phone_number">Phone Number</label>
                <input
                  type="tel"
                  id="phone_number"
                  value={phoneNumber}
                  onChange={handlePhoneNumberChange}
                  placeholder="+919876543210"
                  required
                  disabled={loading}
                  maxLength="13"
                />
                <small>
                  Enter mobile number with +91 prefix (13 characters total)
                </small>
              </div>
              <button 
                type="submit" 
                disabled={loading || !phoneNumber}
              >
                {loading ? (
                  <>
                    <span>🔄</span>
                    <span>Sending OTP...</span>
                  </>
                ) : (
                  <>
                    <span>📤</span>
                    <span>Send OTP</span>
                  </>
                )}
              </button>
            </form>
          ) : (
            // OTP Verification Form
            <form onSubmit={handleVerifyOTP}>
              <div className="form-group">
                <label htmlFor="otp">Enter OTP</label>
                <input
                  type="text"
                  id="otp"
                  value={otp}
                  onChange={handleOTPChange}
                  placeholder="Enter 6-digit OTP"
                  maxLength="6"
                  required
                  disabled={loading}
                  style={{
                    textAlign: 'center',
                    letterSpacing: '2px'
                  }}
                />
                <small>
                  Enter the 6-digit OTP sent to your phone
                </small>
              </div>
              
              <button 
                type="submit" 
                disabled={loading || otp.length !== 6}
                className="otp-verify"
              >
                {loading ? (
                  <>
                    <span>🔄</span>
                    <span>Verifying...</span>
                  </>
                ) : (
                  <>
                    <span>✅</span>
                    <span>Verify OTP</span>
                  </>
                )}
              </button>
              
              <div className="back-button-container">
                <button 
                  type="button" 
                  onClick={handleBackToPhone}
                  disabled={loading}
                  className="back-button"
                >
                  <span>←</span>
                  <span>Back to Phone Number</span>
                </button>
              </div>
            </form>
          )}

          <div className="login-footer">
            <p>
              <a href="#">
                🔑 Forgot Password?
              </a>
            </p>
            <p>
              Don't have an account? 
              <a href="/signup">
                👤 Sign Up
              </a>
            </p>
          </div>
        </div>
      </section>
    </div>
  );
}

export default Login;
